PREFIX orkgr: <http://orkg.org/orkg/resource/>
PREFIX orkgc: <http://orkg.org/orkg/class/>
PREFIX orkgp: <http://orkg.org/orkg/predicate/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
PREFIX rdf: <http://www.w3.org/1999/02/22-rdf-syntax-ns#>

SELECT DISTINCT ?paper ?paperLabel
WHERE {
  {
    SELECT ?paper (COUNT(DISTINCT ?cat) AS ?catCount)
    WHERE {
      ?paper orkgp:P31 ?contribution .
      ?contribution a orkgc:C27001 .
      ?contribution orkgp:P15124 ?da .
      ?da orkgp:P56048 ?ds .
      ?ds orkgp:P57008 ?dispersion .
      {
        ?ds orkgp:P57005 ?ct .
        ?ct orkgp:P47000 ?v .
        BIND("central" AS ?cat)
      }
      UNION {
        ?ds orkgp:P57005 ?ct .
        ?ct orkgp:P57006 ?v .
        BIND("central" AS ?cat)
      }
      UNION {
        ?ds orkgp:P57005 ?ct .
        ?ct orkgp:P57007 ?v .
        BIND("central" AS ?cat)
      }
      UNION {
        ?ds orkgp:P57005 ?ct .
        ?ct orkgp:P44107 ?v .
        BIND("central" AS ?cat)
      }
      UNION {
        ?ds orkgp:P57005 ?ct .
        ?ct orkgp:P44108 ?v .
        BIND("central" AS ?cat)
      }
    }
    GROUP BY ?paper
    HAVING(COUNT(DISTINCT ?cat) >= 2)
  }
  OPTIONAL { ?paper rdfs:label ?paperLabel }
}

PREFIX orkgr: <http://orkg.org/orkg/resource/>
PREFIX orkgc: <http://orkg.org/orkg/class/>
PREFIX orkgp: <http://orkg.org/orkg/predicate/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
PREFIX rdf: <http://www.w3.org/1999/02/22-rdf-syntax-ns#>

SELECT DISTINCT ?paper ?paperLabel
WHERE {
  ?paper orkgp:P31 ?contribution .
  ?contribution a orkgc:C27001 .
  ?contribution orkgp:P39099 ?threats .
  ?threats orkgp:P145000 ?mentioned .
  FILTER NOT EXISTS { ?threats orkgp:P55037 ?x1 . }
  FILTER NOT EXISTS { ?threats orkgp:P55035 ?x2 . }
  FILTER NOT EXISTS { ?threats orkgp:P55034 ?x3 . }
  FILTER NOT EXISTS { ?threats orkgp:P55036 ?x4 . }
  FILTER NOT EXISTS { ?threats orkgp:P59109 ?x5 . }
  FILTER NOT EXISTS { ?threats orkgp:P60006 ?x6 . }
  FILTER NOT EXISTS { ?threats orkgp:P97002 ?x7 . }
  FILTER NOT EXISTS { ?threats orkgp:P68005 ?x8 . }
  FILTER NOT EXISTS { ?threats orkgp:P97000 ?x9 . }
  FILTER NOT EXISTS { ?threats orkgp:P97001 ?x10 . }
  OPTIONAL { ?paper rdfs:label ?paperLabel }
}

PREFIX orkgr: <http://orkg.org/orkg/resource/>
PREFIX orkgc: <http://orkg.org/orkg/class/>
PREFIX orkgp: <http://orkg.org/orkg/predicate/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
PREFIX rdf: <http://www.w3.org/1999/02/22-rdf-syntax-ns#>

SELECT DISTINCT ?paper ?paperLabel
WHERE {
  {
    SELECT ?paper (COUNT(DISTINCT ?cat) AS ?catCount)
    WHERE {
      ?paper orkgp:P31 ?contribution .
      ?contribution a orkgc:C27001 .
      ?contribution orkgp:P15124 ?da .
      ?da orkgp:P56048 ?ds .
      {
        ?ds orkgp:P56049 ?x .
        BIND("frequency" AS ?cat)
      }
      UNION {
        ?ds orkgp:P57005 ?x .
        BIND("central" AS ?cat)
      }
      UNION {
        ?ds orkgp:P57008 ?x .
        BIND("dispersion" AS ?cat)
      }
      UNION {
        ?ds orkgp:P57010 ?x .
        BIND("position" AS ?cat)
      }
    }
    GROUP BY ?paper
  }
  {
    SELECT (MAX(?catCountInner) AS ?maxCount)
    WHERE {
      {
        SELECT ?paperInner (COUNT(DISTINCT ?catInner) AS ?catCountInner)
        WHERE {
          ?paperInner orkgp:P31 ?contributionInner .
          ?contributionInner a orkgc:C27001 .
          ?contributionInner orkgp:P15124 ?daInner .
          ?daInner orkgp:P56048 ?dsInner .
          {
            ?dsInner orkgp:P56049 ?xInner .
            BIND("frequency" AS ?catInner)
          }
          UNION {
            ?dsInner orkgp:P57005 ?xInner .
            BIND("central" AS ?catInner)
          }
          UNION {
            ?dsInner orkgp:P57008 ?xInner .
            BIND("dispersion" AS ?catInner)
          }
          UNION {
            ?dsInner orkgp:P57010 ?xInner .
            BIND("position" AS ?catInner)
          }
        }
        GROUP BY ?paperInner
      }
    }
  }
  FILTER(?catCount = ?maxCount)
  OPTIONAL { ?paper rdfs:label ?paperLabel }
}
